+            .ok()
+            .and_then(|time| time.duration_since(UNIX_EPOCH).ok())
+            .map_or(0, |duration| duration.as_nanos());
+
+        Some(FileFingerprint {
+            len: metadata.len(),
+            modified_ns,
+            inode: metadata.ino(),
+        })
+    }
+
