+    assert_eq!(unsafe { hostent_ipv4(second) }, [198, 51, 100, 7]);
+
+    // SAFETY: integration tests serialize env mutation via TEST_LOCK.
+    unsafe { std::env::remove_var(HOSTS_ENV) };
+    let _ = fs::remove_file(&path);
